export default function QuizzesTab() {
  return <div></div>;
}

import { useState } from 'react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from '@/components/ui/dialog';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Plus, Edit, Trash2, Eye, CheckCircle, XCircle, Clock } from 'lucide-react';

interface QuizResult {
  id: string;
  candidateName: string;
  quizTitle: string;
  position: string;
  completedDate: string;
  score: number;
  totalQuestions: number;
  passingScore: number;
  status: 'passed' | 'failed' | 'pending';
  timeSpent: string;
}

export default function QuizzesTab() {
  const [quizResults, setQuizResults] = useState<QuizResult[]>([]);

  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [viewingResult, setViewingResult] = useState<QuizResult | null>(null);

  const getStatusBadge = (status: string, score: number, passingScore: number) => {
    if (status === 'pending') {
      return (
        <Badge className="bg-yellow-100 text-yellow-800 flex items-center gap-1">
          <Clock className="h-3 w-3" />
          Pending
        </Badge>
      );
    }
    if (status === 'passed') {
      return (
        <Badge className="bg-green-100 text-green-800 flex items-center gap-1">
          <CheckCircle className="h-3 w-3" />
          Passed
        </Badge>
      );
    }
    return (
      <Badge className="bg-red-100 text-red-800 flex items-center gap-1">
        <XCircle className="h-3 w-3" />
        Failed
      </Badge>
    );
  };

  const handleDelete = (id: string) => {
    setQuizResults(quizResults.filter((q) => q.id !== id));
  };

  return (
    <div className="space-y-4">
      <div className="grid gap-4 md:grid-cols-3">
        <Card>
          <CardHeader className="pb-3">
            <CardTitle className="text-sm font-medium text-muted-foreground">
              Total Quizzes
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{quizResults.length}</div>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="pb-3">
            <CardTitle className="text-sm font-medium text-muted-foreground">
              Passed
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-green-600">
              {quizResults.filter((q) => q.status === 'passed').length}
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="pb-3">
            <CardTitle className="text-sm font-medium text-muted-foreground">
              Average Score
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">
              {quizResults.filter((q) => q.status !== 'pending').length > 0
                ? Math.round(
                    quizResults
                      .filter((q) => q.status !== 'pending')
                      .reduce((acc, q) => acc + q.score, 0) /
                      quizResults.filter((q) => q.status !== 'pending').length
                  )
                : 0}
              %
            </div>
          </CardContent>
        </Card>
      </div>

      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">
            <div>
              <CardTitle>Quiz Results</CardTitle>
              <CardDescription>
                Track candidate assessment and quiz performance
              </CardDescription>
            </div>
            <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
              <DialogTrigger asChild>
                <Button onClick={() => setViewingResult(null)}>
                  <Plus className="h-4 w-4 mr-2" />
                  Add Quiz Result
                </Button>
              </DialogTrigger>
              <DialogContent className="max-w-2xl">
                <DialogHeader>
                  <DialogTitle>
                    {viewingResult ? 'Quiz Result Details' : 'Add Quiz Result'}
                  </DialogTitle>
                  <DialogDescription>
                    {viewingResult ? 'View detailed quiz results' : 'Enter quiz result information'}
                  </DialogDescription>
                </DialogHeader>
                <div className="grid gap-4 py-4">
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <Label htmlFor="candidateName">Candidate Name</Label>
                      <Input id="candidateName" placeholder="Sarah Johnson" disabled={!!viewingResult} />
                    </div>
                    <div className="space-y-2">
                      <Label htmlFor="position">Position</Label>
                      <Input id="position" placeholder="Service Provider" disabled={!!viewingResult} />
                    </div>
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="quizTitle">Quiz Title</Label>
                    <Input id="quizTitle" placeholder="Service Provider Assessment" disabled={!!viewingResult} />
                  </div>
                  <div className="grid grid-cols-3 gap-4">
                    <div className="space-y-2">
                      <Label htmlFor="score">Score (%)</Label>
                      <Input id="score" type="number" min="0" max="100" placeholder="85" disabled={!!viewingResult} />
                    </div>
                    <div className="space-y-2">
                      <Label htmlFor="totalQuestions">Total Questions</Label>
                      <Input id="totalQuestions" type="number" placeholder="20" disabled={!!viewingResult} />
                    </div>
                    <div className="space-y-2">
                      <Label htmlFor="passingScore">Passing Score (%)</Label>
                      <Input id="passingScore" type="number" min="0" max="100" placeholder="70" disabled={!!viewingResult} />
                    </div>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <Label htmlFor="completedDate">Completed Date</Label>
                      <Input id="completedDate" type="date" disabled={!!viewingResult} />
                    </div>
                    <div className="space-y-2">
                      <Label htmlFor="timeSpent">Time Spent</Label>
                      <Input id="timeSpent" placeholder="25 min" disabled={!!viewingResult} />
                    </div>
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="status">Status</Label>
                    <Select disabled={!!viewingResult}>
                      <SelectTrigger>
                        <SelectValue placeholder="Select status" />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="pending">Pending</SelectItem>
                        <SelectItem value="passed">Passed</SelectItem>
                        <SelectItem value="failed">Failed</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                </div>
                <DialogFooter>
                  <Button variant="outline" onClick={() => { setIsDialogOpen(false); setViewingResult(null); }}>
                    {viewingResult ? 'Close' : 'Cancel'}
                  </Button>
                  {!viewingResult && (
                    <Button onClick={() => setIsDialogOpen(false)}>
                      Add Result
                    </Button>
                  )}
                </DialogFooter>
              </DialogContent>
            </Dialog>
          </div>
        </CardHeader>
        <CardContent>
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>Candidate</TableHead>
                <TableHead>Quiz Title</TableHead>
                <TableHead>Position</TableHead>
                <TableHead>Score</TableHead>
                <TableHead>Completed</TableHead>
                <TableHead>Time</TableHead>
                <TableHead>Status</TableHead>
                <TableHead className="text-right">Actions</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {quizResults.length === 0 ? (
                <TableRow>
                  <TableCell colSpan={8} className="text-center text-muted-foreground">
                    No quiz results found
                  </TableCell>
                </TableRow>
              ) : (
                quizResults.map((result) => (
                  <TableRow key={result.id}>
                    <TableCell className="font-medium">{result.candidateName}</TableCell>
                    <TableCell>{result.quizTitle}</TableCell>
                    <TableCell>{result.position}</TableCell>
                    <TableCell>
                      {result.status === 'pending' ? (
                        <span className="text-muted-foreground">-</span>
                      ) : (
                        <div className="flex items-center gap-2">
                          <span className="font-semibold">{result.score}%</span>
                          <span className="text-sm text-muted-foreground">
                            ({Math.round((result.score / 100) * result.totalQuestions)}/{result.totalQuestions})
                          </span>
                        </div>
                      )}
                    </TableCell>
                    <TableCell>
                      {result.completedDate ? new Date(result.completedDate).toLocaleDateString() : '-'}
                    </TableCell>
                    <TableCell>{result.timeSpent}</TableCell>
                    <TableCell>{getStatusBadge(result.status, result.score, result.passingScore)}</TableCell>
                    <TableCell className="text-right">
                      <div className="flex justify-end gap-2">
                        <Button
                          variant="ghost"
                          size="icon"
                          onClick={() => {
                            setViewingResult(result);
                            setIsDialogOpen(true);
                          }}
                        >
                          <Eye className="h-4 w-4" />
                        </Button>
                        <Button
                          variant="ghost"
                          size="icon"
                          onClick={() => handleDelete(result.id)}
                        >
                          <Trash2 className="h-4 w-4 text-red-600" />
                        </Button>
                      </div>
                    </TableCell>
                  </TableRow>
                ))
              )}
            </TableBody>
          </Table>
        </CardContent>
      </Card>
    </div>
  );
}
